let aosOption = {
  once: true,
};
AOS.init(aosOption);
console.log(location);

let currentLocation = location.hash;
let mainContent = document.getElementById("main-content");
let screenHeader = document.getElementById("screen-header");
let pageNavigationRoute = document.querySelectorAll(".details-link");

pageNavigationRoute.forEach((element) => {
  if (currentLocation === element.getAttribute("href")) {
    element.classList.add("active");
  } else {
    element.classList.remove("active");
  }
});

window.addEventListener("hashchange", (e) => {
  currentLocation = location.hash;
  routeLoader(currentLocation);
});
function activeRoute(location) {
  pageNavigationRoute.forEach((element) => {
    if (location === element.getAttribute("href")) {
      element.classList.add("active");
    } else if (location === "") {
      pageNavigationRoute[0].classList.add("active");
    } else {
      element.classList.remove("active");
    }
  });
}
function routeLoader(locationHash) {
  activeRoute(locationHash);
  if (locationHash === "#about" || locationHash === "") aboutScreen();
  else if (locationHash === "#resume") resumeScreen();
  else if (locationHash === "#portfolio") portfolioScreen();
  else if (locationHash === "#blog") blogScreen();
  else if (locationHash === "#contact") contactScreen();
}
routeLoader(currentLocation);
